const results = $.steps.searchNotion.response.results || [];
const pages = results.filter(r => r.object === 'page' || r.object === 'database').slice(0, 5).map(r => {
  let title = '';
  if (r.properties) {
    const titleProp = Object.values(r.properties).find(p => p.type === 'title');
    if (titleProp && titleProp.title && titleProp.title.length > 0) {
      title = titleProp.title.map(t => t.plain_text || '').join('');
    }
  }
  if (!title && r.properties && r.properties.Name && r.properties.Name.title) {
    title = r.properties.Name.title.map(t => t.plain_text || '').join('');
  }
  return { id: r.id, title: title || 'Untitled', url: r.url || '', lastEdited: r.last_edited_time || '' };
});
return { pages, pageCount: pages.length };

const pages = $.steps.extractPageIds.output.pages;
const iterations = $.steps.fetchPageContents.response.iterations || [];

let compiled = '';
pages.forEach((page, i) => {
  compiled += '=== PAGE ' + (i + 1) + ': ' + page.title + ' ===\n';
  if (page.url) compiled += 'URL: ' + page.url + '\n';
  if (page.lastEdited) compiled += 'Last edited: ' + page.lastEdited + '\n';
  compiled += '\n';

  const iter = iterations[i];
  if (iter && iter.getBlocks && iter.getBlocks.response) {
    const blocks = iter.getBlocks.response.results || [];
    blocks.forEach(block => {
      const type = block.type;
      if (block[type] && block[type].rich_text) {
        const text = block[type].rich_text.map(t => t.plain_text || '').join('');
        if (text) {
          if (type === 'heading_1') compiled += '# ' + text + '\n';
          else if (type === 'heading_2') compiled += '## ' + text + '\n';
          else if (type === 'heading_3') compiled += '### ' + text + '\n';
          else if (type === 'bulleted_list_item') compiled += '- ' + text + '\n';
          else if (type === 'numbered_list_item') compiled += '1. ' + text + '\n';
          else if (type === 'to_do') compiled += '[ ] ' + text + '\n';
          else compiled += text + '\n';
        }
      }
    });
  }
  compiled += '\n\n';
});

return { compiled: compiled.slice(0, 30000), pageCount: pages.length, pageTitles: pages.map(p => p.title) };

const d = $.steps.compileContent.output;
const question = $.input.question;

let prompt = 'You are a knowledgeable assistant that answers questions using a Notion knowledge base. Answer the following question accurately using ONLY the information found in the Notion pages below. If the answer is not in the pages, say so.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'NOTION KNOWLEDGE BASE (' + d.pageCount + ' pages found):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer based ONLY on the Notion content provided\n';
prompt += '- Cite which page(s) the information comes from using [Page N] notation\n';
prompt += '- If information is partial or unclear, note that\n';
prompt += '- If the answer is not found in any page, clearly state that\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "comprehensive answer citing [Page N] sources",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "sourcesUsed": [{ "pageNumber": 1, "title": "page title", "relevance": "why relevant" }],\n';
prompt += '  "followUpQuestions": ["suggested follow-up 1", "suggested follow-up 2"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', sourcesUsed: [], followUpQuestions: [] }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const pageTitles = $.steps.compileContent.output.pageTitles || [];

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Notion Knowledge Base Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: confidenceEmoji + ' *Confidence:* ' + (ai.confidence || 'medium') + ' | *Pages searched:* ' + pageTitles.length } });
blocks.push({ type: 'divider' });

const answer = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answer } });
blocks.push({ type: 'divider' });

if (ai.sourcesUsed && ai.sourcesUsed.length > 0) {
  let srcText = '*Sources:*\n';
  ai.sourcesUsed.forEach(s => {
    srcText += '[Page ' + s.pageNumber + '] *' + s.title + '* - ' + s.relevance + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 2900) } });
}

if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  let fqText = '*Suggested follow-ups:*\n';
  ai.followUpQuestions.forEach((q, i) => { fqText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fqText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Notion + Claude AI | One CLI' }] });

const fallback = 'KB Answer: ' + (ai.answer || '').slice(0, 100);
return { blocks, fallback };
